import React, { useState } from 'react';
import { loginAdmin } from '../../services/api';
import { FaEnvelope, FaLock } from 'react-icons/fa';

const LoginPage = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await loginAdmin(email, password);
      if (response.data.access_token) {
        onLogin(response.data.access_token);
      }
    } catch (err) {
      setError('Invalid credentials! Use varshini / varshu');
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: '#f5f5f5',
      padding: '20px'
    }}>
      <div style={{
        display: 'flex',
        maxWidth: '1000px',
        width: '100%',
        background: 'white',
        borderRadius: '15px',
        overflow: 'hidden',
        boxShadow: '0 10px 40px rgba(0,0,0,0.1)',
        minHeight: '500px'
      }}>
        {/* Left Side - Brand Section */}
        <div style={{
          flex: 1,
          background: 'linear-gradient(135deg, #e8f0f8 0%, #f0e8f8 100%)',
          padding: '60px 40px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
          textAlign: 'center'
        }}>
          <div>
            <div style={{
              fontSize: '14px',
              fontWeight: '600',
              color: '#4a5568',
              marginBottom: '20px',
              textTransform: 'uppercase',
              letterSpacing: '1px'
            }}>
              🔍 AI Resume
            </div>

            <h1 style={{
              fontSize: '32px',
              fontWeight: 'bold',
              color: '#1a202c',
              marginBottom: '20px',
              lineHeight: '1.4'
            }}>
              Screening System
            </h1>

            <p style={{
              fontSize: '14px',
              color: '#718096',
              lineHeight: '1.6',
              maxWidth: '280px'
            }}>
              AI-Powered Resume Screening Made Simple
            </p>

            {/* Illustration Placeholder */}
            <div style={{
              marginTop: '40px',
              width: '200px',
              height: '150px',
              background: 'rgba(100, 150, 200, 0.1)',
              borderRadius: '10px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '60px'
            }}>
              📋
            </div>
          </div>
        </div>

        {/* Right Side - Login Form */}
        <div style={{
          flex: 1,
          padding: '60px 40px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          background: 'white'
        }}>
          <div>
            {/* Lock Icon */}
            <div style={{
              width: '60px',
              height: '60px',
              background: '#e8f0ff',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              marginBottom: '25px',
              fontSize: '28px',
              color: '#4299e1'
            }}>
              🔒
            </div>

            <h2 style={{
              fontSize: '26px',
              color: '#1a202c',
              marginBottom: '8px',
              fontWeight: '700'
            }}>
              Admin Login
            </h2>
            <p style={{
              color: '#718096',
              fontSize: '14px',
              marginBottom: '30px',
              fontWeight: '500'
            }}>
              Welcome back! Please login to continue.
            </p>

            {error && (
              <div style={{
                background: '#fee',
                color: '#c33',
                padding: '12px 15px',
                borderRadius: '8px',
                marginBottom: '20px',
                fontSize: '13px',
                border: '1px solid #fcc'
              }}>
                {error}
              </div>
            )}

            <form onSubmit={handleSubmit}>
              {/* Email Field */}
              <div style={{
                marginBottom: '20px'
              }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: '#2d3748',
                  fontWeight: '600',
                  fontSize: '13px'
                }}>
                  Email Address
                </label>
                <div style={{
                  position: 'relative'
                }}>
                  <FaEnvelope style={{
                    position: 'absolute',
                    left: '14px',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    color: '#cbd5e0',
                    fontSize: '15px'
                  }} />
                  <input
                    type="email"
                    placeholder="Enter your email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    style={{
                      width: '100%',
                      padding: '12px 14px 12px 42px',
                      border: '1px solid #e2e8f0',
                      borderRadius: '8px',
                      fontSize: '14px',
                      outline: 'none',
                      boxSizing: 'border-box',
                      transition: 'all 0.3s',
                      fontFamily: 'inherit'
                    }}
                    required
                    disabled={loading}
                    onFocus={(e) => {
                      e.target.style.borderColor = '#4299e1';
                      e.target.style.boxShadow = '0 0 0 3px rgba(66, 153, 225, 0.1)';
                    }}
                    onBlur={(e) => {
                      e.target.style.borderColor = '#e2e8f0';
                      e.target.style.boxShadow = 'none';
                    }}
                  />
                </div>
              </div>

              {/* Password Field */}
              <div style={{
                marginBottom: '25px'
              }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: '#2d3748',
                  fontWeight: '600',
                  fontSize: '13px'
                }}>
                  Password
                </label>
                <div style={{
                  position: 'relative'
                }}>
                  <FaLock style={{
                    position: 'absolute',
                    left: '14px',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    color: '#cbd5e0',
                    fontSize: '15px'
                  }} />
                  <input
                    type="password"
                    placeholder="Enter your password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    style={{
                      width: '100%',
                      padding: '12px 14px 12px 42px',
                      border: '1px solid #e2e8f0',
                      borderRadius: '8px',
                      fontSize: '14px',
                      outline: 'none',
                      boxSizing: 'border-box',
                      transition: 'all 0.3s',
                      fontFamily: 'inherit'
                    }}
                    required
                    disabled={loading}
                    onFocus={(e) => {
                      e.target.style.borderColor = '#4299e1';
                      e.target.style.boxShadow = '0 0 0 3px rgba(66, 153, 225, 0.1)';
                    }}
                    onBlur={(e) => {
                      e.target.style.borderColor = '#e2e8f0';
                      e.target.style.boxShadow = 'none';
                    }}
                  />
                </div>
              </div>

              {/* Forgot Password Link */}
              <div style={{
                marginBottom: '25px',
                textAlign: 'right'
              }}>
                <a href="#" style={{
                  fontSize: '13px',
                  color: '#4299e1',
                  textDecoration: 'none',
                  fontWeight: '500',
                  cursor: 'pointer'
                }}
                onMouseEnter={(e) => e.target.style.textDecoration = 'underline'}
                onMouseLeave={(e) => e.target.style.textDecoration = 'none'}
                >
                  Forgot Password?
                </a>
              </div>

              {/* Login Button */}
              <button
                type="submit"
                disabled={loading}
                style={{
                  width: '100%',
                  padding: '12px 16px',
                  background: '#4299e1',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  fontSize: '15px',
                  fontWeight: '600',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  transition: 'all 0.3s',
                  opacity: loading ? 0.7 : 1
                }}
                onMouseEnter={(e) => !loading && (e.target.style.background = '#3182ce')}
                onMouseLeave={(e) => !loading && (e.target.style.background = '#4299e1')}
              >
                {loading ? 'Logging in...' : 'Login'}
              </button>
            </form>
          </div>
        </div>
      </div>

      {/* Footer */}
      <div style={{
        position: 'fixed',
        bottom: '20px',
        left: '0',
        right: '0',
        textAlign: 'center',
        fontSize: '12px',
        color: '#a0aec0'
      }}>
        © 2024 AI Resume Screening System. All rights reserved.
      </div>
    </div>
  );
};

export default LoginPage;
